      out.write("        $('#login-alert').addClass('alert-danger').text(msg).removeClass('d-none');\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    const tokenParam = urlParams.get('token');\n");
      out.write("    if (tokenParam) {\n");
      out.write("        $('#auth-pane').addClass('d-none');\n");
      out.write("        $('#redefinir-pane').removeClass('d-none');\n");
      out.write("        $('#redefinir-token').val(tokenParam);\n");
