      out.write("                        window.location.href = urlDestino;\n");
      out.write("                    }, 1500);\n");
      out.write("                } else {\n");
      out.write("                    alertBox.addClass('alert-danger').text(response.mensagem || 'Credenciais inválidas.').removeClass('d-none');\n");
      out.write("                    btn.prop('disabled', false);\n");
